"use client";

import { useEffect, useState } from "react";
import { supabase } from "@/app/lib/supabase";

const htmlBase64 = "";

function decodeHtml() {
  const binary = window.atob(htmlBase64);
  const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
  return new TextDecoder("utf-8").decode(bytes);
}

export default function Page() {
  useEffect(() => {
    async function applySupabaseProfile() {
      const { data: sessionData } = await supabase.auth.getSession();
      const user = sessionData.session?.user;
      if (!user) return null;

      const { data: profile } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", user.id)
        .single();

      const role = profile?.role || "player";
      const isPremium = !!profile?.is_premium;

      try {
        const w = window as any;
        if (role === "architect" && typeof w.activateArchitectMode === "function") {
          w.activateArchitectMode(user.email || "Architect");
          return { role, isPremium: true };
        }

        if (w.state) {
          const dbLevel = Number(profile?.level || 0);
          const dbXp = Number(profile?.xp || 0);
          const localLevel = Number(w.state.level || 1);
          const localXp = Number(w.state.xp || 0);

          // Load progress from Supabase on login, but do not overwrite newer local progress.
          if (dbLevel > localLevel || (dbLevel === localLevel && dbXp > localXp)) {
            w.state.level = dbLevel || localLevel;
            w.state.xp = dbXp || 0;
          }

          w.state.role = role;
          w.state.isPremium = isPremium;
          if (isPremium) {
            w.state.levelPaymentUnlocked = true;
            w.state.levelPaywallSeen = true;
          }
          if (typeof w.save === "function") w.save();
          if (typeof w.render === "function") w.render();
          if (typeof w.applyPathMenu === "function") w.applyPathMenu();
        }
      } catch {}

      return { role, isPremium };
    }

    (window as any).__showSupabaseLoginForm = function () {
      const box = document.querySelector(".level-login-options");
      if (!box) return;

      box.innerHTML = `
        <div style="display:grid;gap:9px;margin-top:10px">
          <input id="supabaseEmail" type="email" placeholder="EMAIL" autocomplete="email" style="
            width:100%;padding:12px 10px;background:rgba(2,8,24,.96);border:1px solid #6d9eff;color:#dff;
            font-weight:900;text-align:center;box-shadow:0 0 10px rgba(40,114,255,.85);outline:none;
            clip-path:polygon(4% 0,96% 0,100% 20%,100% 80%,96% 100%,4% 100%,0 80%,0 20%);
          " />
          <input id="supabasePassword" type="password" placeholder="PASSWORD" autocomplete="current-password" style="
            width:100%;padding:12px 10px;background:rgba(2,8,24,.96);border:1px solid #6d9eff;color:#dff;
            font-weight:900;text-align:center;box-shadow:0 0 10px rgba(40,114,255,.85);outline:none;
            clip-path:polygon(4% 0,96% 0,100% 20%,100% 80%,96% 100%,4% 100%,0 80%,0 20%);
          " />
          <button onclick="window.__supabaseLoginFromPaywall()" style="
            width:100%;padding:13px 10px;background:rgba(0,120,255,.25);border:1px solid #8fefff;color:#fff;
            font-weight:900;box-shadow:0 0 12px #65d8ff;cursor:pointer;
            clip-path:polygon(5% 0,95% 0,100% 18%,100% 82%,95% 100%,5% 100%,0 82%,0 18%);
          ">SIGN IN</button>
          <button onclick="window.__restoreLoginChoices()" style="
            width:100%;padding:10px;background:rgba(2,8,24,.55);border:1px solid rgba(143,239,255,.55);color:#94f9ff;
            font-weight:900;cursor:pointer;
          ">BACK</button>
        </div>
      `;
    };

    (window as any).__restoreLoginChoices = function () {
      const box = document.querySelector(".level-login-options");
      if (!box) return;
      box.innerHTML = `
        <button onclick="loginLevelGate('Google')">CONTINUE WITH GOOGLE</button>
        <button onclick="loginLevelGate('Apple')">CONTINUE WITH APPLE</button>
        <button onclick="loginLevelGate('Email')">CONTINUE WITH EMAIL</button>
      `;
    };

    (window as any).__supabaseLoginFromPaywall = async function () {
      const email = ((document.getElementById("supabaseEmail") as HTMLInputElement | null)?.value || "").trim();
      const password = (document.getElementById("supabasePassword") as HTMLInputElement | null)?.value || "";

      if (!email || !password) {
        alert("Enter email and password.");
        return;
      }

      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        alert(error.message);
        return;
      }

      const profile = await applySupabaseProfile();
      const w = window as any;

      try {
        if (profile?.role === "architect") {
          if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall();
          if (typeof w.showSystemMessage === "function") {
            w.showSystemMessage("ARCHITECT ACCESS", "ROLE VERIFIED", "Paywall bypass active. Architect Console unlocked.", "rankup", 0, true);
          }
          return;
        }

        if (w.state) {
          w.state.levelLoginUnlocked = true;
          w.state.levelLoginProvider = "Email";
          if (typeof w.save === "function") w.save();
        }

        if (typeof w.showSystemMessage === "function") {
          w.showSystemMessage("LOGIN ACCEPTED", "IDENTITY VERIFIED", "Email account connected. Complete access to continue leveling.", "rankup", 0, true);
        }

        if (profile?.isPremium) {
          if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success");
        } else if (typeof w.levelPaywallStep === "function") {
          w.levelPaywallStep("pay");
        }
      } catch {}
    };

    (window as any).loginWithEmail = async function (email: string, password: string) {
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) {
        alert(error.message);
        return;
      }
      await applySupabaseProfile();
      window.location.reload();
    };


    try {
      (window as any).__beyondSupabase = supabase;
      (window as any).supabaseClient = supabase;

      (window as any).__beyondLoginWithGoogle = async function () {
        const origin = (process.env.NEXT_PUBLIC_SITE_URL || window.location.origin || "https://life-rpg-v6hd.vercel.app").replace(/\/$/, "");
        const { error } = await supabase.auth.signInWithOAuth({
          provider: "google",
          options: { redirectTo: origin }
        });
        if (error) throw error;
      };

      (window as any).__beyondGetAuthSession = async function () {
        const { data } = await supabase.auth.getSession();
        return data.session || null;
      };

      (window as any).__beyondSaveLeaderboardName = async function (name: string) {
        const { data } = await supabase.auth.getSession();
        const user = data.session?.user;
        if (!user) return { error: "No logged in user found." };

        const cleanName = String(name || "PLAYER").trim().slice(0, 24);
        const { data: existing } = await supabase
          .from("profiles")
          .select("role,is_premium,level,xp")
          .eq("id", user.id)
          .maybeSingle();

        const payload = {
          id: user.id,
          email: user.email,
          role: existing?.role || "player",
          is_premium: existing?.is_premium ?? false,
          level: existing?.level ?? 1,
          xp: existing?.xp ?? 0
        };

        const { error } = await supabase
          .from("profiles")
          .upsert(payload, { onConflict: "id" });

        if (error) return { error: error.message || JSON.stringify(error) };

        try {
          localStorage.questPlayerUsername = cleanName.toUpperCase();
          localStorage.playerName = cleanName;
          localStorage.leaderboardName = cleanName;
        } catch {}

        return { ok: true, name: cleanName };
      };

      (window as any).__beyondFetchProfiles = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const uid = sessionData.session?.user?.id || "";
        (window as any).__beyondCurrentUserId = uid;

        const { data, error } = await supabase
          .from("profiles")
          .select("id,email,role,is_premium,level,xp")
          .order("level", { ascending: false })
          .order("xp", { ascending: false });

        if (error || !data) return [];
        return data.map((p: any) => ({
          id: p.id,
          email: p.email,
          name: p.email ? String(p.email).split("@")[0] : "PLAYER",
          level: p.level || 1,
          xp: p.xp || 0,
          role: p.role || "player",
          is_premium: !!p.is_premium
        }));
      };
    } catch {}


    try {
      (window as any).__beyondSyncProgress = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        const w = window as any;
        if (!user || !w.state) return null;

        const { data: existing } = await supabase
          .from("profiles")
          .select("role,is_premium,level,xp")
          .eq("id", user.id)
          .maybeSingle();

        const payload = {
          id: user.id,
          email: user.email,
          role: existing?.role || w.state.role || "player",
          is_premium: existing?.is_premium ?? !!w.state.isPremium,
          level: Number(w.state.level || existing?.level || 1),
          xp: Number(w.state.xp || 0)
        };

        const { error } = await supabase
          .from("profiles")
          .upsert(payload, { onConflict: "id" });

        if (error) {
          console.warn("Progress sync failed:", error.message || error);
          return { error: error.message || String(error) };
        }

        return { ok: true };
      };

      (window as any).__beyondLoadProgress = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        const w = window as any;
        if (!user || !w.state) return null;

        const { data: profile, error } = await supabase
          .from("profiles")
          .select("role,is_premium,level,xp")
          .eq("id", user.id)
          .maybeSingle();

        if (error || !profile) return null;

        const dbLevel = Number(profile.level || 1);
        const dbXp = Number(profile.xp || 0);
        const localLevel = Number(w.state.level || 1);
        const localXp = Number(w.state.xp || 0);

        if (dbLevel > localLevel || (dbLevel === localLevel && dbXp > localXp)) {
          w.state.level = dbLevel;
          w.state.xp = dbXp;
        }

        w.state.role = profile.role || w.state.role || "player";
        w.state.isPremium = !!profile.is_premium;

        if (typeof w.save === "function") w.save();
        if (typeof w.render === "function") w.render();
        if (typeof w.applyPathMenu === "function") w.applyPathMenu();

        return profile;
      };
    } catch {}


    try {
      (window as any).__beyondSupabase = supabase;
      (window as any).supabaseClient = supabase;
      (window as any).__beyondSupabaseSignOut = async function () {
        try { await supabase.auth.signOut(); } catch {}
      };
    } catch {}


    try {
      (window as any).__beyondSupabase = supabase;
      (window as any).supabaseClient = supabase;

      (window as any).__beyondSupabaseSignOut = async function () {
        try { await supabase.auth.signOut(); } catch {}
      };

      (window as any).__beyondGetAuthSession = async function () {
        const { data } = await supabase.auth.getSession();
        return data.session || null;
      };

      (window as any).__beyondGetCurrentProfile = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        if (!user) return null;
        const { data, error } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", user.id)
          .maybeSingle();
        if (error) return null;
        return data || null;
      };

      (window as any).__beyondSaveLeaderboardName = async function (name: string) {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        const w = window as any;
        if (!user) return { error: "No logged in user found." };
        const cleanName = String(name || user.email || "PLAYER").trim().slice(0, 24);
        const { data: existing } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", user.id)
          .maybeSingle();

        const basePayload: any = {
          id: user.id,
          email: user.email,
          role: existing?.role || w.state?.role || "player",
          is_premium: existing?.is_premium ?? !!w.state?.isPremium,
          level: Number(w.state?.level || existing?.level || 1),
          xp: Number(w.state?.xp || existing?.xp || 0)
        };

        const { error } = await supabase
          .from("profiles")
          .upsert(basePayload, { onConflict: "id" });
        if (error) return { error: error.message || JSON.stringify(error) };

        // Optional username columns. Works after you add username/display columns; safely ignored if not present.
        try {
          await supabase.from("profiles").update({
            username: cleanName,
            player_name: cleanName,
            display_name: cleanName
          }).eq("id", user.id);
        } catch {}

        try {
          localStorage.questPlayerUsername = cleanName.toUpperCase();
          localStorage.playerName = cleanName;
          localStorage.leaderboardName = cleanName;
        } catch {}
        if (w.state) {
          w.state.playerName = cleanName;
          w.state.username = cleanName;
          w.state.leaderboardName = cleanName;
        }
        return { ok: true, name: cleanName };
      };

      (window as any).__beyondSyncProgress = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        const w = window as any;
        if (!user || !w.state) return null;
        const { data: existing } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", user.id)
          .maybeSingle();
        const payload: any = {
          id: user.id,
          email: user.email,
          role: existing?.role || w.state.role || "player",
          is_premium: existing?.is_premium ?? !!w.state.isPremium,
          level: Number(w.state.level || existing?.level || 1),
          xp: Number(w.state.xp || 0)
        };
        const { error } = await supabase.from("profiles").upsert(payload, { onConflict: "id" });
        if (error) return { error: error.message || JSON.stringify(error) };
        return { ok: true };
      };

      (window as any).__beyondLoadProgress = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const user = sessionData.session?.user;
        const w = window as any;
        if (!user || !w.state) return null;
        const { data: profile, error } = await supabase
          .from("profiles")
          .select("*")
          .eq("id", user.id)
          .maybeSingle();
        if (error || !profile) return null;
        const dbLevel = Number(profile.level || 1);
        const dbXp = Number(profile.xp || 0);
        const localLevel = Number(w.state.level || 1);
        const localXp = Number(w.state.xp || 0);
        if (dbLevel > localLevel || (dbLevel === localLevel && dbXp > localXp)) {
          w.state.level = dbLevel;
          w.state.xp = dbXp;
        }
        w.state.role = profile.role || w.state.role || "player";
        w.state.isPremium = !!profile.is_premium;
        const storedName = profile.username || profile.player_name || profile.display_name || profile.email;
        if (storedName) {
          const clean = String(storedName).split("@")[0].slice(0, 24);
          w.state.playerName = clean;
          w.state.username = clean;
          w.state.leaderboardName = clean;
          try { localStorage.questPlayerUsername = clean.toUpperCase(); } catch {}
        }
        if (typeof w.save === "function") w.save();
        if (typeof w.render === "function") w.render();
        if (typeof w.applyPathMenu === "function") w.applyPathMenu();
        return profile;
      };

      (window as any).__beyondFetchProfiles = async function () {
        const { data: sessionData } = await supabase.auth.getSession();
        const uid = sessionData.session?.user?.id || "";
        (window as any).__beyondCurrentUserId = uid;
        const { data, error } = await supabase
          .from("profiles")
          .select("*")
          .order("level", { ascending: false })
          .order("xp", { ascending: false });
        if (error || !data) return [];
        return data.map((p: any) => ({
          id: p.id,
          email: p.email,
          username: p.username || p.player_name || p.display_name || (p.email ? String(p.email).split("@")[0] : "PLAYER"),
          name: p.username || p.player_name || p.display_name || (p.email ? String(p.email).split("@")[0] : "PLAYER"),
          level: p.level || 1,
          xp: p.xp || 0,
          role: p.role || "player",
          is_premium: !!p.is_premium
        }));
      };
    } catch {}

    const html = decodeHtml();
    document.open();
    document.write(html);
    document.close();


    const installPremiumGateFix = () => {
      const w = window as any;

      const isPaid = () => {
        try {
          const ls = localStorage.getItem("questAppV1");
          const saved = ls ? JSON.parse(ls) : {};
          return !!(
            w.state?.isPremium ||
            w.state?.levelPaymentUnlocked ||
            saved?.isPremium ||
            saved?.levelPaymentUnlocked
          );
        } catch {
          return !!(w.state?.isPremium || w.state?.levelPaymentUnlocked);
        }
      };

      const markPaid = () => {
        try {
          const current = w.state || {};
          current.isPremium = true;
          current.levelPaymentUnlocked = true;
          current.levelPaywallSeen = true;
          w.state = current;

          try {
            const savedRaw = localStorage.getItem("questAppV1");
            const saved = savedRaw ? JSON.parse(savedRaw) : {};
            saved.isPremium = true;
            saved.levelPaymentUnlocked = true;
            saved.levelPaywallSeen = true;
            localStorage.setItem("questAppV1", JSON.stringify({ ...saved, ...current }));
          } catch {
            localStorage.setItem("questAppV1", JSON.stringify(current));
          }

          if (typeof w.save === "function") w.save();
          if (typeof w.render === "function") w.render();
        } catch {}
      };

      const params = new URLSearchParams(window.location.search);
      if (params.get("payment") === "success") {
        markPaid();
        try {
          if (typeof w.showSystemMessage === "function") {
            w.showSystemMessage(
              "ASCENSION UNLOCKED",
              "PAYMENT CONFIRMED",
              "Your pass is active. Level restrictions removed.",
              "rankup",
              0,
              true
            );
          }
          if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success");
          if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall();
        } catch {}
      }

      if (typeof w.showLevelPaywall === "function" && !w.showLevelPaywall.__premiumWrapped) {
        const originalShow = w.showLevelPaywall;
        const wrappedShow = function () {
          if (isPaid()) {
            markPaid();
            try { if (typeof w.hideLevelPaywall === "function") w.hideLevelPaywall(); } catch {}
            return;
          }
          return originalShow.apply(null, Array.from(arguments) as any);
        };
        (wrappedShow as any).__premiumWrapped = true;
        w.showLevelPaywall = wrappedShow;
      }

      if (typeof w.payLevelGate === "function" && !w.payLevelGate.__premiumWrapped) {
        const originalPay = w.payLevelGate;
        const wrappedPay = async function () {
          if (isPaid()) {
            markPaid();
            try { if (typeof w.levelPaywallStep === "function") w.levelPaywallStep("success"); } catch {}
            return;
          }
          return originalPay.apply(null, Array.from(arguments) as any);
        };
        (wrappedPay as any).__premiumWrapped = true;
        w.payLevelGate = wrappedPay;
      }
    };

    installPremiumGateFix();
    const premiumGateFixTimer = window.setInterval(installPremiumGateFix, 250);
    window.setTimeout(() => window.clearInterval(premiumGateFixTimer), 6000);

    setTimeout(() => {
      applySupabaseProfile();
      installPremiumGateFix();
    }, 500);
  }, []);

  return null;
}
